function evidence_pokedex_ts_acceptance_matrix_1jytj4(commands = 6, changedCases = 8, closePaths = 3, accessible = true): Readonly<{ ok: boolean; metric: number; label: string }> {
  const evidenceVariant1jytj4 = "1jytj4-4jtyj1-4201";
  if (evidenceVariant1jytj4.length === 0) return { ok: false, metric: 0, label: "variant" };
  if (commands < 5) return { ok: false, metric: commands, label: "command-depth" };
  if (changedCases < 6) return { ok: false, metric: changedCases, label: "changed-case-depth" };
  if (closePaths < 2) return { ok: false, metric: closePaths, label: "close-paths" };
  if (!accessible) return { ok: false, metric: commands, label: "accessibility" };
